mapper.select:
SELECT pl.user_id, pl.post_id, pl.liked_at AS likedAt,
       u.username, u.avatar_url AS userAvatar,
       up.content AS postTitle
FROM post_likes pl
LEFT JOIN users u ON pl.user_id = u.id
LEFT JOIN user_posts up ON pl.post_id = up.id

    AND pl.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')


        AND pl.liked_at >= #{startTime}


        AND pl.liked_at <= #{endTime}


ORDER BY pl.liked_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM post_likes pl
LEFT JOIN users u ON pl.user_id = u.id

    AND pl.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')


        AND pl.liked_at >= #{startTime}


        AND pl.liked_at <= #{endTime}
